const required = ['schema_version', 'incident_id', 'source', 'occurred_at', 'environment', 'summary'];
const raw = $input.first().json;
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const payload = body.schema_version ? body : raw;
const missing = required.filter((k) => payload[k] == null || payload[k] === '');
if (missing.length) {
  return [
    {
      json: {
        ok: false,
        error: 'validation_failed',
        missing,
        hint: 'See backend/CONTRACTS.md §3',
      },
    },
  ];
}
return [{ json: { ok: true, incident: payload } }];

const j = $input.first().json;
if (j.ok === false) return [{ json: j }];

const incident = j.incident ?? $('ValidateIncident').first().json.incident;
let oc = j.body ?? j;
if (j.body && typeof j.body === 'object' && !Array.isArray(j.body)) oc = j.body;

const looksLikeOpenClaw =
  oc &&
  typeof oc === 'object' &&
  oc.diagnosis != null &&
  oc.incident_id != null;

if (looksLikeOpenClaw) {
  return [
    {
      json: {
        ok: true,
        incident,
        openclaw: oc,
        _source: 'openclaw_http',
      },
    },
  ];
}

const stub = {
  schema_version: '1.0',
  incident_id: incident.incident_id,
  diagnosis:
    '[stub] OpenClawAnalyze is disabled or response shape did not match §4. Enable node + fix URL/auth with Person C.',
  confidence: 0.5,
  remediation: {
    action: 'NONE',
    target: '',
    namespace: incident.namespace || 'prism',
    payload: '',
  },
  policy_flags: {
    requires_approval: true,
    block_reason: 'Stub / pass-through — no auto-remediation',
  },
};
return [
  {
    json: {
      ok: true,
      incident,
      openclaw: stub,
      _source: 'stub',
    },
  },
];
